function roundRectPath(x,y,w,h,r) {
  ctx.beginPath();
  ctx.moveTo(x+r,y);
  ctx.arcTo(x+w,y,x+w,y+h,r);
  ctx.arcTo(x+w,y+h,x,y+h,r);
  ctx.arcTo(x,y+h,x,y,r);
  ctx.arcTo(x,y,x+w,y,r);
  ctx.closePath();
}

function drawHeart(cx, cy, size) {
  ctx.save();
  ctx.translate(cx, cy);
  ctx.beginPath();
  const top = size * 0.3;
  ctx.moveTo(0, top);
  ctx.bezierCurveTo(0, 0, -size/2, 0, -size/2, top);
  ctx.bezierCurveTo(-size/2, (size+top)/2, 0, (size+top)/2, 0, size);
  ctx.bezierCurveTo(0, (size+top)/2, size/2, (size+top)/2, size/2, top);
  ctx.bezierCurveTo(size/2, 0, 0, 0, 0, top);
  ctx.closePath();
  ctx.fillStyle = '#ff4d6d';
  ctx.fill();
  ctx.strokeStyle = '#c81d4f';
  ctx.lineWidth = 1;
  ctx.stroke();
  ctx.restore();
}

