/* ============ GAME STATE ============ */
let levelIndex = 0;
let camX = 0;
let keys = {};
let timeLeft = 0;
let timerInterval = null;
let running = false;
let hasKey = false;
let animFrame = 0;
let reunionActive = false;
let reunionTimer = 0;
let particles = [];
let dust = [];

const player = {
  x: 40, y: 0, w: 42, h: 56,
  vx: 0, vy: 0,
  onGround: false,
  wasOnGround: false,
  facing: 1,
  squash: 0
};

const GRAVITY = 0.62;
const JUMP_V = -13.5;
const MOVE_SPEED = 3.6;
const FRICTION = 0.8;

function currentLevel() { return LEVELS[levelIndex]; }

function resetPlayerToStart() {
  const lvl = currentLevel();
  player.x = lvl.start.x;
  player.y = lvl.start.y;
  player.vx = 0;
  player.vy = 0;
  player.squash = 0;
  player.wasOnGround = false;
  dust = [];
  camX = 0;
}

function loadLevel(i) {
  levelIndex = i;
  const lvl = currentLevel();
  lvl.key.taken = false;
  hasKey = false;
  document.getElementById('keyStatus').textContent = '🔑 Anahtar yok';
  document.getElementById('levelLabel').textContent = (i+1);
  resetPlayerToStart();
  timeLeft = lvl.time;
  updateTimerBar();
  clearInterval(timerInterval);
  timerInterval = setInterval(() => {
    if (!running) return;
    timeLeft -= 0.1;
    updateTimerBar();
    if (timeLeft <= 0) {
      timeLeft = 0;
      failLevel("Süre doldu!");
    }
  }, 100);
}

function updateTimerBar() {
  const lvl = currentLevel();
  const pct = Math.max(0, (timeLeft / lvl.time) * 100);
  document.getElementById('timerFill').style.width = pct + '%';
}

function failLevel(msg) {
  running = false;
  showOverlay("Kaybettin!", msg + " Bölüm baştan başlıyor.", "Tekrar Dene", () => {
    hideOverlay();
    loadLevel(levelIndex);
    running = true;
  });
}

function startReunion() {
  reunionActive = true;
  reunionTimer = 0;
  particles = [];
  clearInterval(timerInterval);
}

function updateReunion() {
  const lvl = currentLevel();
  reunionTimer++;

  const targetX = lvl.princess.x - player.w - 20;
  if (player.x < targetX) {
    player.x += 2.6;
    player.facing = 1;
  }
  camX = player.x - W/2 + player.w/2;
  if (camX < 0) camX = 0;
  if (camX > lvl.width - W) camX = lvl.width - W;

  if (player.x >= targetX - 4 && reunionTimer % 6 === 0) {
    particles.push({
      x: (lvl.princess.x + player.x + player.w) / 2 + (Math.random()*40-20),
      y: GROUND_Y - 90 + (Math.random()*30-15),
      vy: -0.6 - Math.random()*0.6,
      life: 60,
      size: 3 + Math.random()*3,
      hue: Math.random() < 0.5 ? '#ff4d6d' : '#ff8fab'
    });
  }
  particles.forEach(p => { p.y += p.vy; p.life--; });
  particles = particles.filter(p => p.life > 0);

  animFrame++;

  if (reunionTimer > 210) {
    reunionActive = false;
    winGame();
  }
}

function winGame() {
  running = false;
  clearInterval(timerInterval);
  showOverlay("❤️ Sonunda Kavuştular!", "Uzun ve zorlu bir yolculuğun ardından kalbinin sahibine kavuştu. Beş bölüm boyunca testerelerden, canavarlardan kaçtı, anahtarları bulup kapılara ulaştı. Şimdi yan yanalar ve mutlular. Hikaye burada mutlu sonla bitiyor ❤️", "Baştan Oyna", () => {
    hideOverlay();
    loadLevel(0);
    running = true;
  });
}

function nextLevel() {
  running = false;
  if (levelIndex + 1 >= LEVELS.length) { winGame(); return; }
  showOverlay("Bölüm Tamamlandı!", "Bir sonraki bölüme hazır mısın?", "Devam Et", () => {
    hideOverlay();
    loadLevel(levelIndex + 1);
    running = true;
  });
}

function showOverlay(title, text, btnText, onClick) {
  const ov = document.getElementById('overlay');
  ov.classList.remove('hidden');
  ov.querySelector('h1').textContent = title;
  ov.querySelector('p').textContent = text;
  const btn = document.getElementById('startBtn');
  btn.textContent = btnText;
  btn.onclick = onClick;
}
function hideOverlay() {
  document.getElementById('overlay').classList.add('hidden');
}

/* ============ INPUT ============ */
window.addEventListener('keydown', e => {
  keys[e.code] = true;
  if (['Space','ArrowUp','ArrowLeft','ArrowRight'].includes(e.code)) e.preventDefault();
});
window.addEventListener('keyup', e => keys[e.code] = false);

function bindHold(id, code) {
  const el = document.getElementById(id);
  const on = e => { e.preventDefault(); keys[code] = true; };
  const off = e => { e.preventDefault(); keys[code] = false; };
  el.addEventListener('touchstart', on);
  el.addEventListener('touchend', off);
  el.addEventListener('mousedown', on);
  el.addEventListener('mouseup', off);
  el.addEventListener('mouseleave', off);
}
bindHold('btnLeft','ArrowLeft');
bindHold('btnRight','ArrowRight');
bindHold('btnJump','Space');

function updateControlsVisibility() {
  const isTouch = ('ontouchstart' in window) || navigator.maxTouchPoints > 0 || window.matchMedia('(pointer: coarse)').matches;
  document.getElementById('mobileControls').classList.toggle('hidden', !isTouch);
}
updateControlsVisibility();
window.addEventListener('resize', updateControlsVisibility);

// Mobil tarayıcılarda sayfanın kaymasını / zoom yapmasını engelle
document.addEventListener('touchmove', e => e.preventDefault(), { passive: false });
document.addEventListener('gesturestart', e => e.preventDefault());
document.addEventListener('contextmenu', e => e.preventDefault());

/* ============ PHYSICS / COLLISION ============ */
function rectsOverlap(a, b) {
  return a.x < b.x + b.w && a.x + a.w > b.x && a.y < b.y + b.h && a.y + a.h > b.y;
}

function spawnDust(x, y, count, big) {
  for (let i = 0; i < count; i++) {
    dust.push({
      x: x + (Math.random()*16-8),
      y: y + (Math.random()*4-2),
      vx: (Math.random()*2-1) * (big ? 1.6 : 0.6),
      vy: -(Math.random()*1.6+0.4) * (big ? 1 : 0.6),
      life: big ? 26 + Math.random()*10 : 16 + Math.random()*8,
      maxLife: big ? 32 : 22,
      size: big ? 3 + Math.random()*3 : 1.5 + Math.random()*1.5
    });
  }
}

function update() {
  if (reunionActive) { updateReunion(); return; }
  if (!running) return;
  const lvl = currentLevel();

  if (keys['ArrowLeft']) { player.vx -= 0.9; player.facing = -1; }
  if (keys['ArrowRight']) { player.vx += 0.9; player.facing = 1; }
  player.vx *= FRICTION;
  if (Math.abs(player.vx) > MOVE_SPEED) player.vx = MOVE_SPEED * Math.sign(player.vx);
  if (Math.abs(player.vx) < 0.05) player.vx = 0;

  if ((keys['Space'] || keys['ArrowUp']) && player.onGround) {
    player.vy = JUMP_V;
    player.onGround = false;
  }

  player.vy += GRAVITY;
  if (player.vy > 16) player.vy = 16;

  player.x += player.vx;
  if (player.x < 0) player.x = 0;
  if (player.x > lvl.width - player.w) player.x = lvl.width - player.w;

  player.y += player.vy;
  player.onGround = false;

  const solids = [...lvl.ground, ...lvl.platforms];
  for (const s of solids) {
    if (rectsOverlap(player, s)) {
      const prevBottom = player.y - player.vy + player.h;
      if (player.vy >= 0 && prevBottom <= s.y + 6) {
        player.y = s.y - player.h;
        player.landImpact = player.vy;
        player.vy = 0;
        player.onGround = true;
      } else if (player.vy < 0 && player.y - player.vy >= s.y + s.h - 6) {
        player.y = s.y + s.h;
        player.vy = 0;
      } else {
        if (player.vx > 0) player.x = s.x - player.w;
        else if (player.vx < 0) player.x = s.x + s.w;
      }
    }
  }

  if (player.y > H + 100) {
    failLevel("Boşluğa düştün!");
    return;
  }

  // İniş anında sıkışma animasyonu + toz bulutu
  if (player.onGround && !player.wasOnGround) {
    player.squash = Math.min(1, Math.abs(player.landImpact || 0) / 13);
    if (player.squash > 0.15) spawnDust(player.x + player.w/2, player.y + player.h, 7, true);
  }
  player.wasOnGround = player.onGround;
  player.squash *= 0.82;

  // Koşarken ayak izinde hafif toz
  if (player.onGround && Math.abs(player.vx) > 1.3 && animFrame % 5 === 0) {
    spawnDust(player.x + player.w/2 - player.facing*12, player.y + player.h - 2, 1, false);
  }

  // Toz parçacıklarını güncelle
  for (const d of dust) { d.x += d.vx; d.y += d.vy; d.vy += 0.05; d.life--; }
  dust = dust.filter(d => d.life > 0);

  for (const saw of lvl.saws) {
    saw.x += saw.speed;
    if (saw.x > saw.maxX || saw.x < saw.minX) saw.speed *= -1;
    const sawBox = {x: saw.x - saw.r, y: saw.y - saw.r, w: saw.r*2, h: saw.r*2};
    if (rectsOverlap(player, sawBox)) {
      failLevel("Testereye çarptın!");
      return;
    }
  }

  for (const m of lvl.monsters) {
    m.x += m.speed * m.dir;
    if (m.x > m.xMax || m.x < m.xMin) m.dir *= -1;
    const mBox = {x:m.x,y:m.y,w:m.w,h:m.h};
    if (rectsOverlap(player, mBox)) {
      const prevBottom = player.y - player.vy + player.h;
      if (player.vy > 0 && prevBottom <= m.y + 10) {
        m.dead = true;
        player.vy = JUMP_V * 0.55;
        lvl.monsters = lvl.monsters.filter(mm => !mm.dead);
      } else {
        failLevel("Bir canavar seni yakaladı!");
        return;
      }
    }
  }

  if (!lvl.key.taken && rectsOverlap(player, lvl.key)) {
    lvl.key.taken = true;
    hasKey = true;
    document.getElementById('keyStatus').textContent = '🔑 Anahtar alındı!';
  }

  if (hasKey && rectsOverlap(player, lvl.door)) {
    if (levelIndex === LEVELS.length - 1 && lvl.princess) {
      startReunion();
    } else {
      nextLevel();
    }
    return;
  }

  camX = player.x - W/2 + player.w/2;
  if (camX < 0) camX = 0;
  if (camX > lvl.width - W) camX = lvl.width - W;

  animFrame++;
}

/* ============ RENDER ============ */
function drawRoundRect(x,y,w,h,r,fill) {
  roundRectPath(x,y,w,h,r);
  ctx.fillStyle = fill;
  ctx.fill();
}

// Fotoğraf rozetlerini yumuşak gölge + hafif parlama ile çizer (daha gerçekçi görünüm)
function drawPhotoBadge(img, size, options) {
  options = options || {};
  const radius = options.radius || 14;
  const borderColor = options.borderColor || '#fff';
  const borderWidth = options.borderWidth || 3;
  const fallbackColor = options.fallbackColor || '#f472b6';

  if (img.complete && img.naturalWidth > 0) {
    ctx.save();
    ctx.shadowColor = 'rgba(0,0,0,0.4)';
    ctx.shadowBlur = 14;
    ctx.shadowOffsetY = 6;
    roundRectPath(-size/2, -size/2, size, size, radius);
    ctx.fillStyle = '#ffffff';
    ctx.fill();
    ctx.restore();

    roundRectPath(-size/2, -size/2, size, size, radius);
    ctx.save();
    ctx.clip();
    ctx.drawImage(img, -size/2, -size/2, size, size);
    const sheen = ctx.createLinearGradient(0, -size/2, 0, size/2);
    sheen.addColorStop(0, 'rgba(255,255,255,0.18)');
    sheen.addColorStop(0.35, 'rgba(255,255,255,0)');
    ctx.fillStyle = sheen;
    ctx.fillRect(-size/2, -size/2, size, size);
    ctx.restore();

    ctx.lineWidth = borderWidth;
    ctx.strokeStyle = borderColor;
    roundRectPath(-size/2, -size/2, size, size, radius);
    ctx.stroke();
    return true;
  }
  drawRoundRect(-size/2, -size/2, size, size, radius, fallbackColor);
  return false;
}

function render() {
  ctx.clearRect(0,0,W,H);
  const lvl = currentLevel();

  ctx.save();
  ctx.translate(-camX, 0);

  ctx.fillStyle = 'rgba(255,255,255,0.35)';
  for (let i=0;i<lvl.width;i+=260) {
    ctx.beginPath();
    ctx.ellipse(i+130, GROUND_Y+10, 140, 46, 0, Math.PI, 2*Math.PI);
    ctx.fill();
  }

  for (const g of [...lvl.ground, ...lvl.platforms]) {
    drawRoundRect(g.x, g.y, g.w, g.h, 6, '#8b5e34');
    ctx.fillStyle = '#5fae4a';
    ctx.fillRect(g.x, g.y, g.w, 10);
  }

  for (const saw of lvl.saws) {
    ctx.save();
    ctx.translate(saw.x, saw.y);
    ctx.rotate((animFrame*0.3) % (Math.PI*2));
    ctx.fillStyle = '#c0c0c0';
    ctx.beginPath();
    const spikes = 10;
    for (let i=0;i<spikes*2;i++) {
      const ang = (Math.PI*i)/spikes;
      const rad = i%2===0 ? saw.r : saw.r*0.65;
      ctx.lineTo(Math.cos(ang)*rad, Math.sin(ang)*rad);
    }
    ctx.closePath();
    ctx.fill();
    ctx.fillStyle = '#777';
    ctx.beginPath();
    ctx.arc(0,0,saw.r*0.3,0,Math.PI*2);
    ctx.fill();
    ctx.restore();
  }

  for (const m of lvl.monsters) {
    ctx.fillStyle = '#6b3fa0';
    drawRoundRect(m.x, m.y, m.w, m.h, 8, '#6b3fa0');
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.arc(m.x + m.w*0.3, m.y + m.h*0.35, 4, 0, Math.PI*2);
    ctx.arc(m.x + m.w*0.7, m.y + m.h*0.35, 4, 0, Math.PI*2);
    ctx.fill();
  }

  if (!lvl.key.taken) {
    ctx.save();
    ctx.translate(lvl.key.x + 13, lvl.key.y + 13 + Math.sin(animFrame*0.1)*4);
    ctx.fillStyle = '#facc15';
    ctx.beginPath();
    ctx.arc(-6,0,8,0,Math.PI*2);
    ctx.fill();
    ctx.fillRect(-2,-3,20,6);
    ctx.fillRect(12,-3,4,10);
    ctx.restore();
  }

  const doorOpen = hasKey;
  drawRoundRect(lvl.door.x, lvl.door.y, lvl.door.w, lvl.door.h, 8, doorOpen ? '#4ade80' : '#7c4a2d');
  ctx.fillStyle = '#3a2a1a';
  ctx.fillRect(lvl.door.x + lvl.door.w - 12, lvl.door.y + lvl.door.h/2 - 3, 6, 6);

  // Sevgili (kavuşulacak kişi) - fotoğraf rozeti olarak çizilir
  if (lvl.princess) {
    const p = lvl.princess;
    const sway = Math.sin(animFrame*0.06) * 3;
    const size = 84;
    ctx.save();
    ctx.translate(p.x + p.w/2 + sway, p.y + p.h/2 - 4);

    // gölge / duruş zemini
    ctx.fillStyle = 'rgba(0,0,0,0.15)';
    ctx.beginPath();
    ctx.ellipse(0, size/2 + 6, size*0.32, 7, 0, 0, Math.PI*2);
    ctx.fill();

    const gotBadge = drawPhotoBadge(princessImg, size, { radius: 16, borderWidth: 4, fallbackColor: '#f472b6' });
    if (gotBadge) {
      // kalp (aşk teması)
      const heartBounce = Math.sin(animFrame*0.08) * 3;
      drawHeart(0, -size/2 - 26 + heartBounce, 18);
    }
    ctx.restore();
  }

  // kalp efektleri (kavuşma anı)
  if (particles.length) {
    for (const pt of particles) {
      ctx.save();
      ctx.globalAlpha = Math.max(0, pt.life/60);
      drawHeart(pt.x, pt.y, pt.size*4);
      ctx.restore();
    }
  }

  // koşu ve iniş tozu
  if (dust.length) {
    for (const d of dust) {
      ctx.save();
      ctx.globalAlpha = Math.max(0, d.life / d.maxLife) * 0.55;
      ctx.fillStyle = '#f5e6d8';
      ctx.beginPath();
      ctx.ellipse(d.x, d.y, d.size, d.size*0.7, 0, 0, Math.PI*2);
      ctx.fill();
      ctx.restore();
    }
  }

  // Oyuncu (kahraman) - fotoğraf rozeti
  const bob = player.onGround ? Math.sin(animFrame*0.3) * (Math.abs(player.vx)>0.3 ? 3:0) : 0;
  const heroCx = player.x + player.w/2;
  const heroCy = player.y + player.h/2 + bob;

  // yere düşen gölge: zıplama yüksekliğine göre küçülüp solar (daha gerçekçi zemin bağı)
  const airFactor = Math.min(1, Math.abs(player.vy) / 14);
  ctx.save();
  ctx.translate(heroCx, player.y + player.h + 4);
  ctx.fillStyle = 'rgba(0,0,0,' + (0.22 - airFactor*0.14).toFixed(3) + ')';
  ctx.beginPath();
  ctx.ellipse(0, 0, (player.w*0.42) * (1 - airFactor*0.35), 6 * (1 - airFactor*0.4), 0, 0, Math.PI*2);
  ctx.fill();
  ctx.restore();

  ctx.save();
  ctx.translate(heroCx, heroCy);
  ctx.scale(player.facing, 1);
  // koşarken hafif öne eğilme, zıplarken esneme, inişte sıkışma, dururken nefes alma
  const tilt = Math.max(-0.16, Math.min(0.16, player.vx * 0.05)) * player.facing;
  const jumpStretch = player.onGround ? 0 : Math.max(-0.18, Math.min(0.22, -player.vy * 0.015));
  const idleBreath = (player.onGround && Math.abs(player.vx) < 0.2) ? Math.sin(animFrame*0.05)*0.02 : 0;
  const scaleY = 1 + jumpStretch + idleBreath - player.squash*0.28;
  const scaleX = 1 - jumpStretch*0.6 + player.squash*0.22;
  ctx.rotate(tilt);
  ctx.scale(scaleX, scaleY);
  const spriteSize = player.h + 16;
  drawPhotoBadge(heroImg, spriteSize, { radius: 14, fallbackColor: '#e11d48' });
  ctx.restore();

  ctx.restore(); // kamera

  if (reunionActive && reunionTimer > 60) {
    const alpha = Math.min(1, (reunionTimer - 60) / 40);
    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.font = 'bold 22px Segoe UI, Arial';
    ctx.textAlign = 'center';
    ctx.fillStyle = 'rgba(30,10,15,0.55)';
    ctx.fillText('Sonunda kavuştular ❤️', W/2 + 2, 62);
    ctx.fillStyle = '#fff0f4';
    ctx.fillText('Sonunda kavuştular ❤️', W/2, 60);
    ctx.restore();
  }

  requestAnimationFrame(loop);
}

function loop() {
  update();
  render();
}

/* ============ BAŞLAT ============ */
document.getElementById('startBtn').onclick = () => {
  hideOverlay();
  loadLevel(0);
  running = true;
};

loadLevel(0);
running = false;
requestAnimationFrame(loop);
